364в†’  async prompt(text: string): Promise<PromptResponse> {
365в†’    return this.connection.prompt({
366в†’      sessionId: this.sessionId,
367в†’      prompt: [{ type: 'text', text }],
368в†’    })
369в†’  }
370в†’
371в†’  async cancel(): Promise<void> {
372в†’    await this.connection.cancel({ sessionId: this.sessionId })
373в†’  }
374в†’
375в†’  async destroy(): Promise<void> {
376в†’    // Cleanup terminals
377в†’    for (const [, t] of this.terminals) {
378в†’      t.process.kill('SIGKILL')
