110в†’    try {
111в†’      const start = Date.now()
112в†’      await this.agentInstance.prompt('Reply with only "ready".')
113в†’      this.log.info({ durationMs: Date.now() - start }, 'Warm-up complete')
114в†’    } catch (err) {
115в†’      this.log.error({ err }, 'Warm-up failed')
116в†’    } finally {
117в†’      this.agentInstance.onSessionUpdate = prevHandler
118в†’      this.promptRunning = false
119в†’
120в†’      // Drain any prompts queued while warming up
121в†’      if (this.promptQueue.length > 0) {
122в†’        const next = this.promptQueue.shift()!
123в†’        await this.runPrompt(next)
124в†’      }
125в†’    }
126в†’  }
127в†’
128в†’  async cancel(): Promise<void> {
129в†’    this.status = 'cancelled'
130в†’    this.log.info('Session cancelled')
131в†’    await this.agentInstance.cancel()
132в†’  }
133в†’
134в†’  async destroy(): Promise<void> {
135в†’    this.log.info('Session destroyed')
136в†’    await this.agentInstance.destroy()
137в†’  }
138в†’}
