 1в†’import type { AgentManager } from './agent-manager.js'
 2в†’import { Session } from './session.js'
 3в†’
 4в†’export class SessionManager {
 5в†’  private sessions: Map<string, Session> = new Map()
 6в†’
 7в†’  async createSession(
 8в†’    channelId: string,
 9в†’    agentName: string,
10в†’    workingDirectory: string,
11в†’    agentManager: AgentManager,
12в†’  ): Promise<Session> {
13в†’    const agentInstance = await agentManager.spawn(agentName, workingDirectory)
14в†’    const session = new Session({ channelId, agentName, workingDirectory, agentInstance })
15в†’    this.sessions.set(session.id, session)
16в†’    return session
17в†’  }
18в†’
19в†’  getSession(sessionId: string): Session | undefined {
20в†’    return this.sessions.get(sessionId)
21в†’  }
22в†’
23в†’  getSessionByThread(channelId: string, threadId: string): Session | undefined {
24в†’    for (const session of this.sessions.values()) {
25в†’      if (session.channelId === channelId && session.threadId === threadId) {
26в†’        return session
27в†’      }
28в†’    }
29в†’    return undefined
30в†’  }
31в†’
32в†’  async cancelSession(sessionId: string): Promise<void> {
33в†’    const session = this.sessions.get(sessionId)
34в†’    if (session) await session.cancel()
35в†’  }
36в†’
37в†’  listSessions(channelId?: string): Session[] {
38в†’    const all = Array.from(this.sessions.values())
39в†’    if (channelId) return all.filter(s => s.channelId === channelId)
40в†’    return all
41в†’  }
42в†’
43в†’  async destroyAll(): Promise<void> {
44в†’    for (const session of this.sessions.values()) {
45в†’      await session.destroy()
46в†’    }
47в†’    this.sessions.clear()
48в†’  }
49в†’}
