415в†’  async sendNotification(notification: NotificationMessage): Promise<void> {
416в†’    log.info(
417в†’      { sessionId: notification.sessionId, type: notification.type },
418в†’      "Notification sent",
419в†’    );
420в†’    if (!this.notificationTopicId) return;
421в†’    const emoji: Record<string, string> = {
422в†’      completed: "вњ…",
423в†’      error: "вќЊ",
424в†’      permission: "рџ”ђ",
425в†’      input_required: "рџ’¬",
426в†’    };
427в†’    let text = `${emoji[notification.type] || "в„№пёЏ"} <b>${escapeHtml(notification.sessionName || notification.sessionId)}</b>\n`;
428в†’    text += escapeHtml(notification.summary);
429в†’    if (notification.deepLink) {
430в†’      text += `\n\n<a href="${notification.deepLink}">в†’ Go to message</a>`;
431в†’    }
432в†’    await this.bot.api.sendMessage(this.telegramConfig.chatId, text, {
433в†’      message_thread_id: this.notificationTopicId,
434в†’      parse_mode: "HTML",
