459в†’  async sendSkillCommands(
460в†’    sessionId: string,
461в†’    commands: AgentCommand[],
462в†’  ): Promise<void> {
463в†’    const session = (this.core as OpenACPCore).sessionManager.getSession(
464в†’      sessionId,
465в†’    );
466в†’    if (!session) return;
467в†’    const threadId = Number(session.threadId);
468в†’    if (!threadId) return;
469в†’
470в†’    // Empty commands в†’ remove pinned message
471в†’    if (commands.length === 0) {
472в†’      await this.cleanupSkillCommands(sessionId);
473в†’      return;
474в†’    }
475в†’
476в†’    // Clear old callback entries before building new keyboard
477в†’    clearSkillCallbacks(sessionId);
478в†’
479в†’    const keyboard = buildSkillKeyboard(sessionId, commands);
480в†’    const text = "рџ›  <b>Available commands:</b>";
481в†’    const existingMsgId = this.skillMessages.get(sessionId);
482в†’
483в†’    if (existingMsgId) {
484в†’      // Update existing pinned message
485в†’      try {
486в†’        await this.bot.api.editMessageText(
487в†’          this.telegramConfig.chatId,
488в†’          existingMsgId,
489в†’          text,
490в†’          { parse_mode: "HTML", reply_markup: keyboard },
491в†’        );
492в†’        return;
493в†’      } catch {
494в†’        // Message may have been deleted вЂ” fall through to create new
495в†’      }
496в†’    }
497в†’
498в†’    // Create and pin new message
499в†’    try {
500в†’      const msg = await this.bot.api.sendMessage(
501в†’        this.telegramConfig.chatId,
502в†’        text,
503в†’        {
504в†’          message_thread_id: threadId,
505в†’          parse_mode: "HTML",
506в†’          reply_markup: keyboard,
507в†’          disable_notification: true,
508в†’        },
509в†’      );
510в†’      this.skillMessages.set(sessionId, msg.message_id);
511в†’
512в†’      await this.bot.api.pinChatMessage(
513в†’        this.telegramConfig.chatId,
514в†’        msg.message_id,
515в†’        {
516в†’          disable_notification: true,
517в†’        },
518в†’      );
519в†’    } catch (err) {
520в†’      log.error({ err, sessionId }, "Failed to send skill commands");
521в†’    }
522в†’
523в†’    // Update Telegram autocomplete with skill commands
524в†’    await this.updateCommandAutocomplete(session.agentName, commands);
525в†’  }
526в†’
527в†’  async cleanupSkillCommands(sessionId: string): Promise<void> {
528в†’    const msgId = this.skillMessages.get(sessionId);
529в†’    if (!msgId) return;
530в†’
531в†’    try {
532в†’      await this.bot.api.editMessageText(
533в†’        this.telegramConfig.chatId,
534в†’        msgId,
535в†’        "рџ›  <i>Session ended</i>",
536в†’        { parse_mode: "HTML" },
537в†’      );
538в†’      await this.bot.api.unpinChatMessage(this.telegramConfig.chatId, msgId);
539в†’    } catch {
540в†’      /* message may already be deleted */
541в†’    }
542в†’
543в†’    this.skillMessages.delete(sessionId);
544в†’    clearSkillCallbacks(sessionId);
545в†’  }
546в†’
547в†’  private async updateCommandAutocomplete(
548в†’    agentName: string,
549в†’    skillCommands: AgentCommand[],
550в†’  ): Promise<void> {
551в†’    // Telegram requires: 1-32 chars, lowercase a-z, 0-9, underscores only
552в†’    const prefix = `[${agentName}] `;
553в†’    const validSkills = skillCommands
554в†’      .map((c) => ({
555в†’        command: c.name
556в†’          .toLowerCase()
557в†’          .replace(/[^a-z0-9_]/g, "_")
558в†’          .slice(0, 32),
559в†’        description: (
560в†’          prefix + (c.description || c.name).replace(/\n/g, " ")
561в†’        ).slice(0, 256),
562в†’      }))
563в†’      .filter((c) => c.command.length > 0);
564в†’    const all = [...STATIC_COMMANDS, ...validSkills];
565в†’    try {
566в†’      await this.bot.api.setMyCommands(all, {
567в†’        scope: { type: "chat", chat_id: this.telegramConfig.chatId },
568в†’      });
569в†’      log.info(
570в†’        { count: all.length, skills: validSkills.length },
571в†’        "Updated command autocomplete",
572в†’      );
573в†’    } catch (err) {
574в†’      log.error(
575в†’        { err, commands: all },
576в†’        "Failed to update command autocomplete",
577в†’      );
578в†’    }
579в†’  }
580в†’
581в†’  private async finalizeDraft(sessionId: string): Promise<void> {
582в†’    const draft = this.sessionDrafts.get(sessionId);
583в†’    if (draft) {
584в†’      await draft.finalize();
585в†’      this.sessionDrafts.delete(sessionId);
586в†’    }
587в†’  }
588в†’}
