299в†’export function buildSkillKeyboard(
300в†’  sessionId: string,
301в†’  commands: AgentCommand[],
302в†’): InlineKeyboard {
303в†’  const keyboard = new InlineKeyboard()
304в†’  const sorted = [...commands].sort((a, b) => a.name.localeCompare(b.name))
305в†’  for (let i = 0; i < sorted.length; i++) {
306в†’    const cmd = sorted[i]
307в†’    const key = nanoid(8)
308в†’    skillCallbackMap.set(key, { sessionId, commandName: cmd.name })
309в†’    keyboard.text(`/${cmd.name}`, `s:${key}`)
310в†’    if (i % 2 === 1 && i < sorted.length - 1) {
311в†’      keyboard.row()
312в†’    }
313в†’  }
314в†’  return keyboard
315в†’}
