1136в†’const MODEL_CONTEXT_HINT_PATTERN = /\[(\d+m)\]$/i;
1137в†’function tokenizeModelPreference(model) {
1138в†’    const lower = model.trim().toLowerCase();
1139в†’    const contextHint = lower.match(MODEL_CONTEXT_HINT_PATTERN)?.[1]?.toLowerCase();
1140в†’    const normalized = lower.replace(MODEL_CONTEXT_HINT_PATTERN, " $1 ");
1141в†’    const rawTokens = normalized.split(/[^a-z0-9]+/).filter(Boolean);
1142в†’    const tokens = rawTokens
