1144в†’        if (token === "opusplan")
1145в†’            return "opus";
1146в†’        if (token === "best" || token === "default")
1147в†’            return "";
1148в†’        return token;
1149в†’    })
1150в†’        .filter((token) => token && token !== "claude")
1151в†’        .filter((token) => /[a-z]/.test(token) || token.endsWith("m"));
