1168в†’    const lower = trimmed.toLowerCase();
1169в†’    // Exact match on value or display name
1170в†’    const directMatch = models.find((model) => model.value === trimmed ||
1171в†’        model.value.toLowerCase() === lower ||
1172в†’        model.displayName.toLowerCase() === lower);
1173в†’    if (directMatch)
1174в†’        return directMatch;
1175в†’    // Substring match
1176в†’    const includesMatch = models.find((model) => {
1177в†’        const value = model.value.toLowerCase();
1178в†’        const display = model.displayName.toLowerCase();
1179в†’        return value.includes(lower) || display.includes(lower) || lower.includes(value);
1180в†’    });
1181в†’    if (includesMatch)
1182в†’        return includesMatch;
1183в†’    // Tokenized matching for aliases like "opus[1m]"
1184в†’    const { tokens, contextHint } = tokenizeModelPreference(trimmed);
1185в†’    if (tokens.length === 0)
