1187в†’    let bestMatch = null;
1188в†’    let bestScore = 0;
1189в†’    for (const model of models) {
1190в†’        const score = scoreModelMatch(model, tokens, contextHint);
1191в†’        if (0 < score && (!bestMatch || bestScore < score)) {
1192в†’            bestMatch = model;
1193в†’            bestScore = score;
1194в†’        }
1195в†’    }
1196в†’    return bestMatch;
