 14в†’        path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
 15в†’    ];
 16в†’    for (const jsPath of packageDirs) {
 17в†’        if (fs.existsSync(jsPath)) {
 18в†’            return { command: process.execPath, args: [jsPath] };
 19в†’        }
 20в†’    }
 21в†’    // 2. Check local .bin вЂ” if it's a JS file with shebang, run with node directly
 22в†’    const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd);
 23в†’    if (fs.existsSync(localBin)) {
 24в†’        const content = fs.readFileSync(localBin, 'utf-8');
 25в†’        if (content.startsWith('#!/usr/bin/env node')) {
 26в†’            return { command: process.execPath, args: [localBin] };
 27в†’        }
 28в†’        // Shell wrapper вЂ” try to find the target JS file
 29в†’        const match = content.match(/"([^"]+\.js)"/);
 30в†’        if (match) {
 31в†’            const target = path.resolve(path.dirname(localBin), match[1]);
 32в†’            if (fs.existsSync(target)) {
 33в†’                return { command: process.execPath, args: [target] };
 34в†’            }
 35в†’        }
 36в†’    }
 37в†’    // 3. Try resolving from PATH using which
 38в†’    try {
 39в†’        const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim();
 40в†’        if (fullPath) {
 41в†’            const content = fs.readFileSync(fullPath, 'utf-8');
 42в†’            if (content.startsWith('#!/usr/bin/env node')) {
 43в†’                return { command: process.execPath, args: [fullPath] };
 44в†’            }
 45в†’        }
 46в†’    }
 47в†’    catch {
 48в†’        // which failed
 49в†’    }
 50в†’    // 4. Fallback: use command as-is
 51в†’    return { command: cmd, args: [] };
