  1в†’import { spawn, execSync, type ChildProcess } from 'node:child_process'
  2в†’import { Transform } from 'node:stream'
  3в†’import fs from 'node:fs'
  4в†’import path from 'node:path'
  5в†’import { randomUUID } from 'node:crypto'
  6в†’import { ClientSideConnection, ndJsonStream } from '@agentclientprotocol/sdk'
  7в†’import type { Agent, Client, PromptResponse, PermissionOption as SdkPermissionOption } from '@agentclientprotocol/sdk'
  8в†’import { nodeToWebWritable, nodeToWebReadable } from './streams.js'
  9в†’import { StderrCapture } from './stderr-capture.js'
 10в†’import type { AgentDefinition, AgentEvent, PermissionRequest } from './types.js'
 11в†’import { createChildLogger } from './log.js'
 12в†’const log = createChildLogger({ module: 'agent-instance' })
 13в†’
 14в†’/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
 15в†’function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
 16в†’  // 1. Check local node_modules for the package's actual JS entry point
 17в†’  const packageDirs = [
 18в†’    path.resolve(process.cwd(), 'node_modules', '@zed-industries', cmd, 'dist', 'index.js'),
 19в†’    path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
 20в†’  ]
 21в†’  for (const jsPath of packageDirs) {
 22в†’    if (fs.existsSync(jsPath)) {
 23в†’      return { command: process.execPath, args: [jsPath] }
 24в†’    }
 25в†’  }
 26в†’
 27в†’  // 2. Check local .bin вЂ” if it's a JS file with shebang, run with node directly
 28в†’  const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd)
 29в†’  if (fs.existsSync(localBin)) {
 30в†’    const content = fs.readFileSync(localBin, 'utf-8')
 31в†’    if (content.startsWith('#!/usr/bin/env node')) {
 32в†’      return { command: process.execPath, args: [localBin] }
 33в†’    }
 34в†’    // Shell wrapper вЂ” try to find the target JS file
 35в†’    const match = content.match(/"([^"]+\.js)"/)
 36в†’    if (match) {
 37в†’      const target = path.resolve(path.dirname(localBin), match[1])
 38в†’      if (fs.existsSync(target)) {
 39в†’        return { command: process.execPath, args: [target] }
 40в†’      }
 41в†’    }
 42в†’  }
 43в†’
 44в†’  // 3. Try resolving from PATH using which
 45в†’  try {
 46в†’    const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim()
 47в†’    if (fullPath) {
 48в†’      const content = fs.readFileSync(fullPath, 'utf-8')
 49в†’      if (content.startsWith('#!/usr/bin/env node')) {
 50в†’        return { command: process.execPath, args: [fullPath] }
 51в†’      }
 52в†’    }
 53в†’  } catch {
 54в†’    // which failed
 55в†’  }
 56в†’
 57в†’  // 4. Fallback: use command as-is
 58в†’  return { command: cmd, args: [] }
 59в†’}
 60в†’
 61в†’interface TerminalState {
 62в†’  process: ChildProcess
 63в†’  output: string
 64в†’  exitStatus: { exitCode: number | null; signal: string | null } | null
 65в†’}
 66в†’
 67в†’export class AgentInstance {
 68в†’  private connection!: ClientSideConnection
 69в†’  private child!: ChildProcess
 70в†’  private stderrCapture!: StderrCapture
 71в†’  private terminals: Map<string, TerminalState> = new Map()
 72в†’
 73в†’  sessionId!: string
 74в†’  agentName: string
 75в†’
 76в†’  // Callbacks вЂ” set by core when wiring events
 77в†’  onSessionUpdate: (event: AgentEvent) => void = () => {}
 78в†’  onPermissionRequest: (request: PermissionRequest) => Promise<string> = async () => ''
 79в†’
 80в†’  private constructor(agentName: string) {
 81в†’    this.agentName = agentName
 82в†’  }
 83в†’
 84в†’  static async spawn(agentDef: AgentDefinition, workingDirectory: string): Promise<AgentInstance> {
 85в†’    const instance = new AgentInstance(agentDef.name)
 86в†’
 87в†’    // 1. Resolve command: find the actual JS entry point to avoid shell wrappers
 88в†’    const resolved = resolveAgentCommand(agentDef.command)
 89в†’    log.debug({ agentName: agentDef.name, command: resolved.command, args: resolved.args }, 'Spawning agent')
 90в†’    const spawnStart = Date.now()
 91в†’
 92в†’    // Spawn subprocess
 93в†’    instance.child = spawn(resolved.command, [...resolved.args, ...agentDef.args], {
 94в†’      stdio: ['pipe', 'pipe', 'pipe'],
 95в†’      cwd: workingDirectory,
 96в†’      env: { ...process.env, ...agentDef.env },
 97в†’    })
 98в†’
 99в†’    // 2. Handle spawn errors (e.g., command not found)
100в†’    await new Promise<void>((resolve, reject) => {
101в†’      instance.child.on('error', (err) => {
102в†’        reject(new Error(`Failed to spawn agent "${agentDef.name}": ${err.message}. Is "${agentDef.command}" installed?`))
103в†’      })
104в†’      instance.child.on('spawn', () => resolve())
105в†’    })
106в†’
107в†’    // 3. Capture stderr
108в†’    instance.stderrCapture = new StderrCapture(50)
109в†’    instance.child.stderr!.on('data', (chunk: Buffer) => {
110в†’      instance.stderrCapture.append(chunk.toString())
111в†’    })
112в†’
113в†’    // 3. Create ACP stream with raw NDJSON logging
114в†’    const stdinLogger = new Transform({
115в†’      transform(chunk, _enc, cb) {
116в†’        log.debug({ direction: 'send', raw: chunk.toString().trimEnd() }, 'ACP raw')
117в†’        cb(null, chunk)
118в†’      },
119в†’    })
120в†’    stdinLogger.pipe(instance.child.stdin!)
121в†’
122в†’    const stdoutLogger = new Transform({
123в†’      transform(chunk, _enc, cb) {
124в†’        log.debug({ direction: 'recv', raw: chunk.toString().trimEnd() }, 'ACP raw')
125в†’        cb(null, chunk)
126в†’      },
127в†’    })
128в†’    instance.child.stdout!.pipe(stdoutLogger)
129в†’
130в†’    const toAgent = nodeToWebWritable(stdinLogger)
131в†’    const fromAgent = nodeToWebReadable(stdoutLogger)
132в†’    const stream = ndJsonStream(toAgent, fromAgent)
133в†’
134в†’    // 4. Create ClientSideConnection
135в†’    instance.connection = new ClientSideConnection(
136в†’      (_agent: Agent): Client => instance.createClient(_agent),
137в†’      stream,
138в†’    )
139в†’
140в†’    // 5. ACP handshake
141в†’    await instance.connection.initialize({
142в†’      protocolVersion: 1,
143в†’      clientCapabilities: {
144в†’        fs: { readTextFile: true, writeTextFile: true },
145в†’        terminal: true,
146в†’      },
147в†’    })
148в†’
149в†’    // 6. Create session
150в†’    const response = await instance.connection.newSession({
151в†’      cwd: workingDirectory,
152в†’      mcpServers: [],
153в†’    })
154в†’    instance.sessionId = response.sessionId
155в†’
156в†’    // 7. Crash detection
157в†’    instance.child.on('exit', (code, signal) => {
158в†’      log.info({ sessionId: instance.sessionId, exitCode: code, signal }, 'Agent process exited')
159в†’      if (code !== 0 && code !== null) {
160в†’        const stderr = instance.stderrCapture.getLastLines()
161в†’        instance.onSessionUpdate({
162в†’          type: 'error',
163в†’          message: `Agent crashed (exit code ${code})\n${stderr}`,
164в†’        })
165в†’      }
166в†’    })
167в†’
168в†’    instance.connection.closed.then(() => {
169в†’      log.debug({ sessionId: instance.sessionId }, 'ACP connection closed')
170в†’    })
171в†’
172в†’    log.info({ sessionId: response.sessionId, durationMs: Date.now() - spawnStart }, 'Agent spawn complete')
173в†’    return instance
174в†’  }
175в†’
176в†’  // createClient вЂ” implemented in Task 6b
177в†’  private createClient(_agent: Agent): Client {
178в†’    const self = this
179в†’    const MAX_OUTPUT_BYTES = 1024 * 1024 // 1MB cap
180в†’
181в†’    return {
182в†’      // в”Ђв”Ђ Session updates в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
183в†’      async sessionUpdate(params) {
184в†’        const update = params.update
185в†’        let event: AgentEvent | null = null
186в†’
187в†’        switch (update.sessionUpdate) {
188в†’          case 'agent_message_chunk':
189в†’            if (update.content.type === 'text') {
190в†’              event = { type: 'text', content: update.content.text }
191в†’            }
192в†’            break
193в†’          case 'agent_thought_chunk':
194в†’            if (update.content.type === 'text') {
195в†’              event = { type: 'thought', content: update.content.text }
196в†’            }
197в†’            break
198в†’          case 'tool_call':
199в†’            event = {
200в†’              type: 'tool_call',
201в†’              id: update.toolCallId,
202в†’              name: update.title,
203в†’              kind: update.kind ?? undefined,
204в†’              status: update.status ?? 'pending',
205в†’              content: update.content ?? undefined,
206в†’            }
207в†’            break
208в†’          case 'tool_call_update':
209в†’            event = {
210в†’              type: 'tool_update',
211в†’              id: update.toolCallId,
212в†’              status: update.status ?? 'pending',
213в†’              content: update.content ?? undefined,
214в†’            }
215в†’            break
216в†’          case 'plan':
217в†’            event = { type: 'plan', entries: update.entries }
218в†’            break
219в†’          case 'usage_update':
220в†’            event = {
221в†’              type: 'usage',
222в†’              tokensUsed: update.used,
223в†’              contextSize: update.size,
224в†’              cost: update.cost ?? undefined,
225в†’            }
226в†’            break
227в†’          case 'available_commands_update':
228в†’            event = { type: 'commands_update', commands: update.availableCommands }
229в†’            break
230в†’          default:
231в†’            // Unknown update type вЂ” ignore
232в†’            return
233в†’        }
234в†’
235в†’        if (event !== null) {
236в†’          self.onSessionUpdate(event)
237в†’        }
238в†’      },
239в†’
240в†’      // в”Ђв”Ђ Permission requests в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
241в†’      async requestPermission(params) {
242в†’        const permissionRequest: PermissionRequest = {
243в†’          id: params.toolCall.toolCallId,
244в†’          description: params.toolCall.title ?? params.toolCall.toolCallId,
245в†’          options: params.options.map((opt: SdkPermissionOption) => ({
246в†’            id: opt.optionId,
247в†’            label: opt.name,
248в†’            isAllow: opt.kind === 'allow_once' || opt.kind === 'allow_always',
249в†’          })),
250в†’        }
251в†’
252в†’        const selectedOptionId = await self.onPermissionRequest(permissionRequest)
253в†’        return {
254в†’          outcome: { outcome: 'selected' as const, optionId: selectedOptionId },
255в†’        }
256в†’      },
257в†’
258в†’      // в”Ђв”Ђ File operations в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
259в†’      async readTextFile(params) {
260в†’        const content = await fs.promises.readFile(params.path, 'utf-8')
261в†’        return { content }
262в†’      },
263в†’
264в†’      async writeTextFile(params) {
265в†’        await fs.promises.mkdir(path.dirname(params.path), { recursive: true })
266в†’        await fs.promises.writeFile(params.path, params.content, 'utf-8')
267в†’        return {}
268в†’      },
269в†’
270в†’      // в”Ђв”Ђ Terminal operations в”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђв”Ђ
271в†’      async createTerminal(params) {
272в†’        const terminalId = randomUUID()
273в†’        const args = params.args ?? []
274в†’        const env: Record<string, string> = {}
275в†’        for (const ev of params.env ?? []) {
276в†’          env[ev.name] = ev.value
277в†’        }
278в†’
279в†’        const childProcess = spawn(params.command, args, {
280в†’          cwd: params.cwd ?? undefined,
281в†’          env: { ...process.env, ...env },
282в†’          shell: false,
283в†’        })
284в†’
285в†’        const state: TerminalState = {
286в†’          process: childProcess,
287в†’          output: '',
288в†’          exitStatus: null,
289в†’        }
290в†’        self.terminals.set(terminalId, state)
291в†’
292в†’        const outputByteLimit = params.outputByteLimit ?? MAX_OUTPUT_BYTES
293в†’
294в†’        const appendOutput = (chunk: string) => {
295в†’          state.output += chunk
296в†’          // Truncate from the beginning if over limit
297в†’          const bytes = Buffer.byteLength(state.output, 'utf-8')
298в†’          if (bytes > outputByteLimit) {
299в†’            // Find truncation point at character boundary
300в†’            const excess = bytes - outputByteLimit
301в†’            state.output = state.output.slice(excess)
302в†’          }
303в†’        }
304в†’
305в†’        childProcess.stdout?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
306в†’        childProcess.stderr?.on('data', (chunk: Buffer) => appendOutput(chunk.toString()))
307в†’
308в†’        childProcess.on('exit', (code, signal) => {
309в†’          state.exitStatus = { exitCode: code, signal }
310в†’        })
311в†’
312в†’        return { terminalId }
313в†’      },
314в†’
315в†’      async terminalOutput(params) {
316в†’        const state = self.terminals.get(params.terminalId)
317в†’        if (!state) {
318в†’          throw new Error(`Terminal not found: ${params.terminalId}`)
319в†’        }
320в†’        return {
321в†’          output: state.output,
322в†’          truncated: false,
323в†’          exitStatus: state.exitStatus
324в†’            ? { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
325в†’            : undefined,
326в†’        }
327в†’      },
328в†’
329в†’      async waitForTerminalExit(params) {
330в†’        const state = self.terminals.get(params.terminalId)
331в†’        if (!state) {
332в†’          throw new Error(`Terminal not found: ${params.terminalId}`)
333в†’        }
334в†’        if (state.exitStatus !== null) {
335в†’          return { exitCode: state.exitStatus.exitCode, signal: state.exitStatus.signal }
336в†’        }
337в†’        return new Promise((resolve) => {
338в†’          state.process.on('exit', (code, signal) => {
339в†’            resolve({ exitCode: code, signal })
340в†’          })
341в†’        })
342в†’      },
343в†’
344в†’      async killTerminal(params) {
345в†’        const state = self.terminals.get(params.terminalId)
346в†’        if (!state) {
347в†’          throw new Error(`Terminal not found: ${params.terminalId}`)
348в†’        }
349в†’        state.process.kill('SIGTERM')
350в†’        return {}
351в†’      },
352в†’
353в†’      async releaseTerminal(params) {
354в†’        const state = self.terminals.get(params.terminalId)
355в†’        if (!state) {
356в†’          return
357в†’        }
358в†’        state.process.kill('SIGKILL')
359в†’        self.terminals.delete(params.terminalId)
360в†’      },
361в†’    }
362в†’  }
363в†’
364в†’  async prompt(text: string): Promise<PromptResponse> {
365в†’    return this.connection.prompt({
366в†’      sessionId: this.sessionId,
367в†’      prompt: [{ type: 'text', text }],
368в†’    })
369в†’  }
370в†’
371в†’  async cancel(): Promise<void> {
372в†’    await this.connection.cancel({ sessionId: this.sessionId })
373в†’  }
374в†’
375в†’  async destroy(): Promise<void> {
376в†’    // Cleanup terminals
377в†’    for (const [, t] of this.terminals) {
378в†’      t.process.kill('SIGKILL')
379в†’    }
380в†’    this.terminals.clear()
381в†’
382в†’    // Kill agent subprocess
383в†’    this.child.kill('SIGTERM')
384в†’    setTimeout(() => {
385в†’      if (!this.child.killed) this.child.kill('SIGKILL')
386в†’    }, 10_000)
387в†’  }
388в†’}
