 56в†’
 57в†’  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
 58в†’    super(core, config as never);
 59в†’    this.telegramConfig = config;
 60в†’  }
 61в†’
 62в†’  async start(): Promise<void> {
 63в†’    this.bot = new Bot(this.telegramConfig.botToken, { client: { fetch } });
 64в†’
 65в†’    // Global error handler вЂ” prevent unhandled errors from crashing the bot
 66в†’    this.bot.catch((err) => {
 67в†’      const rootCause = err.error instanceof Error ? err.error : err;
 68в†’      log.error({ err: rootCause }, "Telegram bot error");
 69в†’    });
 70в†’
 71в†’    // Ensure allowed_updates includes callback_query on every poll.
 72в†’    // bot.start() passes allowed_updates, but grammY only sends it on the first
 73в†’    // getUpdates call. Subsequent polls may omit the parameter, causing Telegram
 74в†’    // to fall back to its default (which excludes callback_query). This transformer
 75в†’    // guarantees callback_query is always requested.
 76в†’    this.bot.api.config.use((prev, method, payload, signal) => {
 77в†’      if (method === "getUpdates") {
 78в†’        const p = payload as never as Record<string, unknown>;
 79в†’        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
 80в†’          "message",
 81в†’          "callback_query",
 82в†’        ];
 83в†’      }
 84в†’      return prev(method, payload, signal);
 85в†’    });
 86в†’
 87в†’    // Register static commands for Telegram autocomplete (scoped to this chat)
 88в†’    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
 89в†’      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
 90в†’    });
 91в†’
 92в†’    // Middleware: only accept updates from configured chatId
 93в†’    this.bot.use((ctx, next) => {
 94в†’      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
 95в†’      if (chatId !== this.telegramConfig.chatId) return;
 96в†’      return next();
 97в†’    });
 98в†’
 99в†’    // Ensure system topics exist
100в†’    const topics = await ensureTopics(
101в†’      this.bot,
102в†’      this.telegramConfig.chatId,
103в†’      this.telegramConfig,
104в†’      async (updates) => {
105в†’        // Save topic IDs to config
106в†’        await (this.core as OpenACPCore).configManager.save({
107в†’          channels: { telegram: updates },
108в†’        });
109в†’      },
110в†’    );
111в†’    this.notificationTopicId = topics.notificationTopicId;
112в†’    this.assistantTopicId = topics.assistantTopicId;
113в†’
114в†’    // Setup permission handler (instance only, callback registered later)
115в†’    this.permissionHandler = new PermissionHandler(
116в†’      this.bot,
117в†’      this.telegramConfig.chatId,
118в†’      (sessionId) =>
119в†’        (this.core as OpenACPCore).sessionManager.getSession(sessionId),
120в†’      (notification) => this.sendNotification(notification),
121в†’    );
122в†’
123в†’    // Callback registration order matters!
124в†’    // Specific regex handlers first, catch-all last.
125в†’    setupSkillCallbacks(this.bot, this.core as OpenACPCore);
126в†’    setupMenuCallbacks(
127в†’      this.bot,
128в†’      this.core as OpenACPCore,
129в†’      this.telegramConfig.chatId,
130в†’    );
131в†’    setupCommands(
132в†’      this.bot,
133в†’      this.core as OpenACPCore,
134в†’      this.telegramConfig.chatId,
135в†’    );
136в†’    this.permissionHandler.setupCallbackHandler();
137в†’
138в†’    // Setup message routing
139в†’    this.setupRoutes();
140в†’
141в†’    // Start bot polling
142в†’    this.bot.start({
143в†’      allowed_updates: ["message", "callback_query"],
144в†’      onStart: () =>
145в†’        log.info(
146в†’          { chatId: this.telegramConfig.chatId },
147в†’          "Telegram bot started",
148в†’        ),
149в†’    });
150в†’
151в†’    // Spawn assistant (after bot is started so it can send messages)
152в†’    try {
153в†’      this.assistantSession = await spawnAssistant(
154в†’        this.core as OpenACPCore,
155в†’        this,
156в†’        this.assistantTopicId,
157в†’      );
158в†’    } catch (err) {
159в†’      log.error({ err }, "Failed to spawn assistant");
160в†’    }
161в†’
162в†’    // Send welcome message with menu to assistant topic
163в†’    try {
164в†’      const config = (this.core as OpenACPCore).configManager.get();
165в†’      const agents = (
166в†’        this.core as OpenACPCore
167в†’      ).agentManager.getAvailableAgents();
168в†’      const agentList = agents
169в†’        .map(
170в†’          (a) =>
171в†’            `${escapeHtml(a.name)}${a.name === config.defaultAgent ? " (default)" : ""}`,
172в†’        )
173в†’        .join(", ");
174в†’      const workspace = escapeHtml(config.workspace.baseDir);
175в†’
176в†’      const welcomeText =
177в†’        `рџ‘‹ <b>OpenACP Assistant</b> is online.\n\n` +
178в†’        `Available agents: ${agentList}\n` +
179в†’        `Workspace: <code>${workspace}</code>\n\n` +
180в†’        `<b>Select an action:</b>`;
181в†’
182в†’      await this.bot.api.sendMessage(this.telegramConfig.chatId, welcomeText, {
183в†’        message_thread_id: this.assistantTopicId,
184в†’        parse_mode: "HTML",
185в†’        reply_markup: buildMenuKeyboard(),
186в†’      });
187в†’    } catch (err) {
188в†’      log.warn({ err }, "Failed to send welcome message");
189в†’    }
190в†’  }
