192в†’  async stop(): Promise<void> {
193в†’    if (this.assistantSession) {
194в†’      await this.assistantSession.destroy();
195в†’    }
196в†’    await this.bot.stop();
197в†’    log.info("Telegram bot stopped");
198в†’  }
