241в†’  async sendMessage(
242в†’    sessionId: string,
243в†’    content: OutgoingMessage,
244в†’  ): Promise<void> {
245в†’    // log.debug({ sessionId, type: content.type }, "Sending message to Telegram");
246в†’    const session = (this.core as OpenACPCore).sessionManager.getSession(
247в†’      sessionId,
248в†’    );
249в†’    if (!session) return;
250в†’    const threadId = Number(session.threadId);
251в†’
252в†’    switch (content.type) {
253в†’      case "thought": {
254в†’        // Skip thought/thinking content вЂ” it's internal agent reasoning
255в†’        // Users don't need to see it
256в†’        break;
257в†’      }
258в†’
259в†’      case "text": {
260в†’        let draft = this.sessionDrafts.get(sessionId);
261в†’        if (!draft) {
262в†’          draft = new MessageDraft(
263в†’            this.bot,
264в†’            this.telegramConfig.chatId,
265в†’            threadId,
266в†’          );
267в†’          this.sessionDrafts.set(sessionId, draft);
268в†’        }
269в†’        draft.append(content.text);
270в†’        break;
271в†’      }
272в†’
273в†’      case "tool_call": {
274в†’        await this.finalizeDraft(sessionId);
275в†’        const meta = content.metadata as never as {
276в†’          id: string;
277в†’          name: string;
278в†’          kind?: string;
279в†’          status?: string;
280в†’          content?: unknown;
281в†’        };
282в†’        const msg = await this.bot.api.sendMessage(
283в†’          this.telegramConfig.chatId,
284в†’          formatToolCall(meta),
285в†’          {
286в†’            message_thread_id: threadId,
287в†’            parse_mode: "HTML",
288в†’            disable_notification: true,
289в†’          },
290в†’        );
291в†’        if (!this.toolCallMessages.has(sessionId)) {
292в†’          this.toolCallMessages.set(sessionId, new Map());
293в†’        }
294в†’        this.toolCallMessages.get(sessionId)!.set(meta.id, {
295в†’          msgId: msg.message_id,
296в†’          name: meta.name,
297в†’          kind: meta.kind,
298в†’        });
299в†’        break;
300в†’      }
301в†’
302в†’      case "tool_update": {
303в†’        const meta = content.metadata as never as {
304в†’          id: string;
305в†’          name: string;
306в†’          kind?: string;
307в†’          status: string;
308в†’          content?: unknown;
309в†’        };
310в†’        const toolState = this.toolCallMessages.get(sessionId)?.get(meta.id);
311в†’        if (toolState) {
312в†’          // Merge name/kind from original tool_call
313в†’          const merged = {
314в†’            ...meta,
315в†’            name: meta.name || toolState.name,
316в†’            kind: meta.kind || toolState.kind,
317в†’          };
318в†’          try {
319в†’            await this.bot.api.editMessageText(
320в†’              this.telegramConfig.chatId,
321в†’              toolState.msgId,
322в†’              formatToolUpdate(merged),
323в†’              { parse_mode: "HTML" },
324в†’            );
325в†’          } catch {
326в†’            /* edit failed */
327в†’          }
328в†’        }
329в†’        break;
330в†’      }
331в†’
332в†’      case "plan": {
333в†’        await this.finalizeDraft(sessionId);
334в†’        await this.bot.api.sendMessage(
335в†’          this.telegramConfig.chatId,
336в†’          formatPlan(
337в†’            content.metadata as never as {
338в†’              entries: Array<{ content: string; status: string }>;
339в†’            },
340в†’          ),
341в†’          {
342в†’            message_thread_id: threadId,
343в†’            parse_mode: "HTML",
344в†’            disable_notification: true,
345в†’          },
346в†’        );
347в†’        break;
348в†’      }
349в†’
350в†’      case "usage": {
351в†’        // Show usage stats
352в†’        await this.bot.api.sendMessage(
353в†’          this.telegramConfig.chatId,
354в†’          formatUsage(
355в†’            content.metadata as never as {
356в†’              tokensUsed?: number;
357в†’              contextSize?: number;
358в†’              cost?: { amount: number; currency: string };
359в†’            },
360в†’          ),
361в†’          {
362в†’            message_thread_id: threadId,
363в†’            parse_mode: "HTML",
364в†’            disable_notification: true,
365в†’          },
366в†’        );
367в†’        break;
368в†’      }
369в†’
370в†’      case "session_end": {
371в†’        await this.finalizeDraft(sessionId);
372в†’        this.sessionDrafts.delete(sessionId);
373в†’        this.toolCallMessages.delete(sessionId);
374в†’        await this.cleanupSkillCommands(sessionId);
375в†’        await this.bot.api.sendMessage(
376в†’          this.telegramConfig.chatId,
377в†’          `вњ… <b>Done</b>`,
378в†’          {
379в†’            message_thread_id: threadId,
380в†’            parse_mode: "HTML",
381в†’            disable_notification: true,
382в†’          },
383в†’        );
384в†’        break;
385в†’      }
386в†’
387в†’      case "error": {
388в†’        await this.finalizeDraft(sessionId);
389в†’        await this.bot.api.sendMessage(
390в†’          this.telegramConfig.chatId,
391в†’          `вќЊ <b>Error:</b> ${escapeHtml(content.text)}`,
392в†’          {
393в†’            message_thread_id: threadId,
394в†’            parse_mode: "HTML",
395в†’            disable_notification: true,
396в†’          },
397в†’        );
398в†’        break;
399в†’      }
400в†’    }
401в†’  }
