 75в†’export class ConfigManager {
 76в†’  private config!: Config
 77в†’  private configPath: string
 78в†’
 79в†’  constructor() {
 80в†’    this.configPath = process.env.OPENACP_CONFIG_PATH || expandHome('~/.openacp/config.json')
 81в†’  }
 82в†’
 83в†’  async load(): Promise<void> {
 84в†’    // 1. Ensure directory exists
 85в†’    const dir = path.dirname(this.configPath)
 86в†’    fs.mkdirSync(dir, { recursive: true })
 87в†’
 88в†’    // 2. If config file doesn't exist, create default
 89в†’    if (!fs.existsSync(this.configPath)) {
 90в†’      fs.writeFileSync(this.configPath, JSON.stringify(DEFAULT_CONFIG, null, 2))
 91в†’      log.info({ configPath: this.configPath }, 'Config created')
 92в†’      log.info('Please edit it with your Telegram bot token and chat ID, then restart.')
 93в†’      process.exit(1)
 94в†’    }
 95в†’
 96в†’    // 3. Read and parse
 97в†’    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))
 98в†’
 99в†’    // 4. Apply env var overrides
100в†’    this.applyEnvOverrides(raw)
101в†’
102в†’    // 5. Validate with Zod
103в†’    const result = ConfigSchema.safeParse(raw)
104в†’    if (!result.success) {
105в†’      log.error('Config validation failed')
106в†’      for (const issue of result.error.issues) {
107в†’        log.error({ path: issue.path.join('.'), message: issue.message }, 'Validation error')
108в†’      }
109в†’      process.exit(1)
110в†’    }
111в†’    this.config = result.data
112в†’  }
113в†’
114в†’  get(): Config {
115в†’    return this.config
116в†’  }
117в†’
118в†’  async save(updates: Record<string, unknown>): Promise<void> {
119в†’    // Read current file, merge updates, write back
120в†’    const raw = JSON.parse(fs.readFileSync(this.configPath, 'utf-8'))
121в†’    this.deepMerge(raw, updates)
122в†’    fs.writeFileSync(this.configPath, JSON.stringify(raw, null, 2))
123в†’    // Re-validate and update in-memory config
124в†’    const result = ConfigSchema.safeParse(raw)
125в†’    if (result.success) {
126в†’      this.config = result.data
127в†’    }
128в†’  }
129в†’
130в†’  resolveWorkspace(input?: string): string {
131в†’    if (!input) {
132в†’      const resolved = expandHome(this.config.workspace.baseDir)
133в†’      fs.mkdirSync(resolved, { recursive: true })
134в†’      return resolved
135в†’    }
136в†’    if (input.startsWith('/') || input.startsWith('~')) {
137в†’      const resolved = expandHome(input)
138в†’      fs.mkdirSync(resolved, { recursive: true })
139в†’      return resolved
140в†’    }
141в†’    // Named workspace в†’ lowercase, under baseDir
142в†’    const name = input.toLowerCase()
143в†’    const resolved = path.join(expandHome(this.config.workspace.baseDir), name)
144в†’    fs.mkdirSync(resolved, { recursive: true })
145в†’    return resolved
146в†’  }
147в†’
148в†’  async exists(): Promise<boolean> {
149в†’    return fs.existsSync(this.configPath)
150в†’  }
151в†’
152в†’  getConfigPath(): string {
153в†’    return this.configPath
154в†’  }
155в†’
156в†’  async writeNew(config: Config): Promise<void> {
157в†’    const dir = path.dirname(this.configPath)
158в†’    fs.mkdirSync(dir, { recursive: true })
159в†’    fs.writeFileSync(this.configPath, JSON.stringify(config, null, 2))
160в†’  }
161в†’
162в†’  private applyEnvOverrides(raw: Record<string, unknown>): void {
163в†’    const overrides: [string, string[]][] = [
164в†’      ['OPENACP_TELEGRAM_BOT_TOKEN', ['channels', 'telegram', 'botToken']],
165в†’      ['OPENACP_TELEGRAM_CHAT_ID', ['channels', 'telegram', 'chatId']],
166в†’      ['OPENACP_DEFAULT_AGENT', ['defaultAgent']],
167в†’    ]
168в†’    for (const [envVar, configPath] of overrides) {
169в†’      const value = process.env[envVar]
170в†’      if (value !== undefined) {
171в†’        let target = raw as Record<string, any>
172в†’        for (let i = 0; i < configPath.length - 1; i++) {
173в†’          if (!target[configPath[i]]) target[configPath[i]] = {}
174в†’          target = target[configPath[i]]
175в†’        }
176в†’        const key = configPath[configPath.length - 1]
177в†’        // Convert chatId to number
178в†’        target[key] = key === 'chatId' ? Number(value) : value
179в†’      }
180в†’    }
181в†’
182в†’    // Logging env var overrides
183в†’    if (process.env.OPENACP_LOG_LEVEL) {
184в†’      raw.logging = raw.logging || {}
185в†’      ;(raw.logging as Record<string, unknown>).level = process.env.OPENACP_LOG_LEVEL
186в†’    }
187в†’    if (process.env.OPENACP_LOG_DIR) {
188в†’      raw.logging = raw.logging || {}
189в†’      ;(raw.logging as Record<string, unknown>).logDir = process.env.OPENACP_LOG_DIR
190в†’    }
191в†’    if (process.env.OPENACP_DEBUG && !process.env.OPENACP_LOG_LEVEL) {
192в†’      raw.logging = raw.logging || {}
193в†’      ;(raw.logging as Record<string, unknown>).level = 'debug'
194в†’    }
195в†’  }
196в†’
197в†’  private deepMerge(target: Record<string, any>, source: Record<string, any>): void {
198в†’    for (const key of Object.keys(source)) {
199в†’      if (source[key] && typeof source[key] === 'object' && !Array.isArray(source[key])) {
200в†’        if (!target[key]) target[key] = {}
201в†’        this.deepMerge(target[key], source[key])
202в†’      } else {
203в†’        target[key] = source[key]
204в†’      }
205в†’    }
206в†’  }
207в†’}
