  1в†’import { nanoid } from 'nanoid'
  2в†’import type { AgentInstance } from './agent-instance.js'
  3в†’import type { ChannelAdapter } from './channel.js'
  4в†’import type { SessionStatus } from './types.js'
  5в†’import { createChildLogger, createSessionLogger, type Logger } from './log.js'
  6в†’const moduleLog = createChildLogger({ module: 'session' })
  7в†’
  8в†’export class Session {
  9в†’  id: string
 10в†’  channelId: string
 11в†’  threadId: string = ''
 12в†’  agentName: string
 13в†’  workingDirectory: string
 14в†’  agentInstance: AgentInstance
 15в†’  status: SessionStatus = 'initializing'
 16в†’  name?: string
 17в†’  promptQueue: string[] = []
 18в†’  promptRunning: boolean = false
 19в†’  createdAt: Date = new Date()
 20в†’  adapter?: ChannelAdapter  // Set by wireSessionEvents for renaming
 21в†’  pendingPermission?: { requestId: string; resolve: (optionId: string) => void }
 22в†’  log: Logger
 23в†’
 24в†’  constructor(opts: {
 25в†’    id?: string
 26в†’    channelId: string
 27в†’    agentName: string
 28в†’    workingDirectory: string
 29в†’    agentInstance: AgentInstance
 30в†’  }) {
 31в†’    this.id = opts.id || nanoid(12)
 32в†’    this.channelId = opts.channelId
 33в†’    this.agentName = opts.agentName
 34в†’    this.workingDirectory = opts.workingDirectory
 35в†’    this.agentInstance = opts.agentInstance
 36в†’    this.log = createSessionLogger(this.id, moduleLog)
 37в†’    this.log.info({ agentName: this.agentName }, 'Session created')
 38в†’  }
 39в†’
 40в†’  async enqueuePrompt(text: string): Promise<void> {
 41в†’    if (this.promptRunning) {
 42в†’      this.promptQueue.push(text)
 43в†’      this.log.debug({ queueDepth: this.promptQueue.length }, 'Prompt queued')
 44в†’      return
 45в†’    }
 46в†’    await this.runPrompt(text)
 47в†’  }
 48в†’
 49в†’  private async runPrompt(text: string): Promise<void> {
 50в†’    this.promptRunning = true
 51в†’    this.status = 'active'
 52в†’    const promptStart = Date.now()
 53в†’    this.log.debug('Prompt execution started')
 54в†’
 55в†’    try {
 56в†’      await this.agentInstance.prompt(text)
 57в†’      this.log.info({ durationMs: Date.now() - promptStart }, 'Prompt execution completed')
 58в†’
 59в†’      // Auto-name after first user prompt
 60в†’      if (!this.name) {
 61в†’        await this.autoName()
 62в†’      }
 63в†’    } catch (err) {
 64в†’      this.status = 'error'
 65в†’      this.log.error({ err }, 'Prompt execution failed')
 66в†’    } finally {
 67в†’      this.promptRunning = false
 68в†’
 69в†’      // Process next queued prompt
 70в†’      if (this.promptQueue.length > 0) {
 71в†’        const next = this.promptQueue.shift()!
 72в†’        await this.runPrompt(next)
 73в†’      }
 74в†’    }
 75в†’  }
 76в†’
 77в†’  // NOTE: This injects a summary prompt into the agent's conversation history.
 78в†’  // Known Phase 1 limitation вЂ” the agent sees this prompt in its context.
 79в†’  private async autoName(): Promise<void> {
 80в†’    let title = ''
 81в†’    const prevHandler = this.agentInstance.onSessionUpdate
 82в†’    this.agentInstance.onSessionUpdate = (event) => {
 83в†’      if (event.type === 'text') title += event.content
 84в†’    }
 85в†’
 86в†’    try {
 87в†’      await this.agentInstance.prompt(
 88в†’        'Summarize this conversation in max 5 words for a topic title. Reply ONLY with the title, nothing else.'
 89в†’      )
 90в†’      this.name = title.trim().slice(0, 50)
 91в†’      this.log.info({ name: this.name }, 'Session auto-named')
 92в†’
 93в†’      // Rename the topic on the channel
 94в†’      if (this.adapter && this.name) {
 95в†’        await this.adapter.renameSessionThread(this.id, this.name)
 96в†’      }
 97в†’    } catch {
 98в†’      this.name = `Session ${this.id.slice(0, 6)}`
 99в†’    } finally {
100в†’      this.agentInstance.onSessionUpdate = prevHandler
101в†’    }
102в†’  }
103в†’
104в†’  /** Fire-and-forget warm-up: primes model cache while user types their first message */
105в†’  async warmup(): Promise<void> {
106в†’    this.promptRunning = true
107в†’    const prevHandler = this.agentInstance.onSessionUpdate
108в†’    this.agentInstance.onSessionUpdate = () => {} // suppress warm-up output
109в†’
110в†’    try {
111в†’      const start = Date.now()
112в†’      await this.agentInstance.prompt('Reply with only "ready".')
113в†’      this.log.info({ durationMs: Date.now() - start }, 'Warm-up complete')
114в†’    } catch (err) {
115в†’      this.log.error({ err }, 'Warm-up failed')
116в†’    } finally {
117в†’      this.agentInstance.onSessionUpdate = prevHandler
118в†’      this.promptRunning = false
119в†’
120в†’      // Drain any prompts queued while warming up
121в†’      if (this.promptQueue.length > 0) {
122в†’        const next = this.promptQueue.shift()!
123в†’        await this.runPrompt(next)
124в†’      }
125в†’    }
126в†’  }
127в†’
128в†’  async cancel(): Promise<void> {
129в†’    this.status = 'cancelled'
130в†’    this.log.info('Session cancelled')
131в†’    await this.agentInstance.cancel()
132в†’  }
133в†’
134в†’  async destroy(): Promise<void> {
135в†’    this.log.info('Session destroyed')
136в†’    await this.agentInstance.destroy()
137в†’  }
138в†’}
