 14в†’/** Resolve an agent command to a directly executable form (avoids shell wrappers) */
 15в†’function resolveAgentCommand(cmd: string): { command: string; args: string[] } {
 16в†’  // 1. Check local node_modules for the package's actual JS entry point
 17в†’  const packageDirs = [
 18в†’    path.resolve(process.cwd(), 'node_modules', '@zed-industries', cmd, 'dist', 'index.js'),
 19в†’    path.resolve(process.cwd(), 'node_modules', cmd, 'dist', 'index.js'),
 20в†’  ]
 21в†’  for (const jsPath of packageDirs) {
 22в†’    if (fs.existsSync(jsPath)) {
 23в†’      return { command: process.execPath, args: [jsPath] }
 24в†’    }
 25в†’  }
 26в†’
 27в†’  // 2. Check local .bin вЂ” if it's a JS file with shebang, run with node directly
 28в†’  const localBin = path.resolve(process.cwd(), 'node_modules', '.bin', cmd)
 29в†’  if (fs.existsSync(localBin)) {
 30в†’    const content = fs.readFileSync(localBin, 'utf-8')
 31в†’    if (content.startsWith('#!/usr/bin/env node')) {
 32в†’      return { command: process.execPath, args: [localBin] }
 33в†’    }
 34в†’    // Shell wrapper вЂ” try to find the target JS file
 35в†’    const match = content.match(/"([^"]+\.js)"/)
 36в†’    if (match) {
 37в†’      const target = path.resolve(path.dirname(localBin), match[1])
 38в†’      if (fs.existsSync(target)) {
 39в†’        return { command: process.execPath, args: [target] }
 40в†’      }
 41в†’    }
 42в†’  }
 43в†’
 44в†’  // 3. Try resolving from PATH using which
 45в†’  try {
 46в†’    const fullPath = execSync(`which ${cmd}`, { encoding: 'utf-8' }).trim()
 47в†’    if (fullPath) {
 48в†’      const content = fs.readFileSync(fullPath, 'utf-8')
 49в†’      if (content.startsWith('#!/usr/bin/env node')) {
 50в†’        return { command: process.execPath, args: [fullPath] }
 51в†’      }
 52в†’    }
 53в†’  } catch {
 54в†’    // which failed
 55в†’  }
 56в†’
 57в†’  // 4. Fallback: use command as-is
 58в†’  return { command: cmd, args: [] }
 59в†’}
 60в†’
 61в†’interface TerminalState {
 62в†’  process: ChildProcess
 63в†’  output: string
 64в†’  exitStatus: { exitCode: number | null; signal: string | null } | null
 65в†’}
 66в†’
 67в†’export class AgentInstance {
 68в†’  private connection!: ClientSideConnection
 69в†’  private child!: ChildProcess
 70в†’  private stderrCapture!: StderrCapture
 71в†’  private terminals: Map<string, TerminalState> = new Map()
 72в†’
 73в†’  sessionId!: string
 74в†’  agentName: string
 75в†’
 76в†’  // Callbacks вЂ” set by core when wiring events
 77в†’  onSessionUpdate: (event: AgentEvent) => void = () => {}
 78в†’  onPermissionRequest: (request: PermissionRequest) => Promise<string> = async () => ''
 79в†’
 80в†’  private constructor(agentName: string) {
 81в†’    this.agentName = agentName
 82в†’  }
 83в†’
 84в†’  static async spawn(agentDef: AgentDefinition, workingDirectory: string): Promise<AgentInstance> {
 85в†’    const instance = new AgentInstance(agentDef.name)
 86в†’
 87в†’    // 1. Resolve command: find the actual JS entry point to avoid shell wrappers
 88в†’    const resolved = resolveAgentCommand(agentDef.command)
 89в†’    log.debug({ agentName: agentDef.name, command: resolved.command, args: resolved.args }, 'Spawning agent')
 90в†’    const spawnStart = Date.now()
 91в†’
 92в†’    // Spawn subprocess
 93в†’    instance.child = spawn(resolved.command, [...resolved.args, ...agentDef.args], {
 94в†’      stdio: ['pipe', 'pipe', 'pipe'],
 95в†’      cwd: workingDirectory,
 96в†’      env: { ...process.env, ...agentDef.env },
 97в†’    })
 98в†’
 99в†’    // 2. Handle spawn errors (e.g., command not found)
100в†’    await new Promise<void>((resolve, reject) => {
101в†’      instance.child.on('error', (err) => {
102в†’        reject(new Error(`Failed to spawn agent "${agentDef.name}": ${err.message}. Is "${agentDef.command}" installed?`))
103в†’      })
104в†’      instance.child.on('spawn', () => resolve())
105в†’    })
106в†’
107в†’    // 3. Capture stderr
108в†’    instance.stderrCapture = new StderrCapture(50)
109в†’    instance.child.stderr!.on('data', (chunk: Buffer) => {
110в†’      instance.stderrCapture.append(chunk.toString())
111в†’    })
112в†’
113в†’    // 3. Create ACP stream with raw NDJSON logging
114в†’    const stdinLogger = new Transform({
115в†’      transform(chunk, _enc, cb) {
116в†’        log.debug({ direction: 'send', raw: chunk.toString().trimEnd() }, 'ACP raw')
117в†’        cb(null, chunk)
118в†’      },
119в†’    })
120в†’    stdinLogger.pipe(instance.child.stdin!)
121в†’
122в†’    const stdoutLogger = new Transform({
123в†’      transform(chunk, _enc, cb) {
124в†’        log.debug({ direction: 'recv', raw: chunk.toString().trimEnd() }, 'ACP raw')
125в†’        cb(null, chunk)
126в†’      },
127в†’    })
128в†’    instance.child.stdout!.pipe(stdoutLogger)
129в†’
130в†’    const toAgent = nodeToWebWritable(stdinLogger)
131в†’    const fromAgent = nodeToWebReadable(stdoutLogger)
132в†’    const stream = ndJsonStream(toAgent, fromAgent)
133в†’
134в†’    // 4. Create ClientSideConnection
135в†’    instance.connection = new ClientSideConnection(
136в†’      (_agent: Agent): Client => instance.createClient(_agent),
137в†’      stream,
138в†’    )
139в†’
140в†’    // 5. ACP handshake
141в†’    await instance.connection.initialize({
142в†’      protocolVersion: 1,
143в†’      clientCapabilities: {
144в†’        fs: { readTextFile: true, writeTextFile: true },
145в†’        terminal: true,
146в†’      },
147в†’    })
148в†’
149в†’    // 6. Create session
150в†’    const response = await instance.connection.newSession({
151в†’      cwd: workingDirectory,
152в†’      mcpServers: [],
153в†’    })
154в†’    instance.sessionId = response.sessionId
155в†’
156в†’    // 7. Crash detection
157в†’    instance.child.on('exit', (code, signal) => {
158в†’      log.info({ sessionId: instance.sessionId, exitCode: code, signal }, 'Agent process exited')
159в†’      if (code !== 0 && code !== null) {
160в†’        const stderr = instance.stderrCapture.getLastLines()
161в†’        instance.onSessionUpdate({
162в†’          type: 'error',
163в†’          message: `Agent crashed (exit code ${code})\n${stderr}`,
164в†’        })
165в†’      }
166в†’    })
167в†’
168в†’    instance.connection.closed.then(() => {
169в†’      log.debug({ sessionId: instance.sessionId }, 'ACP connection closed')
170в†’    })
171в†’
172в†’    log.info({ sessionId: response.sessionId, durationMs: Date.now() - spawnStart }, 'Agent spawn complete')
173в†’    return instance
174в†’  }
