 1в†’import type { Config } from './config.js'
 2в†’import type { AgentDefinition } from './types.js'
 3в†’import { AgentInstance } from './agent-instance.js'
 4в†’
 5в†’export class AgentManager {
 6в†’  constructor(private config: Config) {}
 7в†’
 8в†’  getAvailableAgents(): AgentDefinition[] {
 9в†’    return Object.entries(this.config.agents).map(([name, cfg]) => ({
10в†’      name,
11в†’      command: cfg.command,
12в†’      args: cfg.args,
13в†’      workingDirectory: cfg.workingDirectory,
14в†’      env: cfg.env,
15в†’    }))
16в†’  }
17в†’
18в†’  getAgent(name: string): AgentDefinition | undefined {
19в†’    const cfg = this.config.agents[name]
20в†’    if (!cfg) return undefined
21в†’    return { name, ...cfg }
22в†’  }
