24в†’  async spawn(agentName: string, workingDirectory: string): Promise<AgentInstance> {
25в†’    const agentDef = this.getAgent(agentName)
26в†’    if (!agentDef) throw new Error(`Agent "${agentName}" not found in config`)
27в†’    return AgentInstance.spawn(agentDef, workingDirectory)
28в†’  }
29в†’}
