 80в†’async function handleNew(
 81в†’  ctx: Context,
 82в†’  core: OpenACPCore,
 83в†’  chatId: number,
 84в†’): Promise<void> {
 85в†’  const rawMatch = (ctx as Context & { match: unknown }).match;
 86в†’  const matchStr = typeof rawMatch === "string" ? rawMatch : "";
 87в†’  const args = matchStr.split(" ").filter(Boolean);
 88в†’  const agentName = args[0];
 89в†’  const workspace = args[1];
 90в†’
 91в†’  log.info({ userId: ctx.from?.id, agentName }, 'New session command')
 92в†’
 93в†’  // Create topic first so threadId is ready before session events fire
 94в†’  let threadId: number | undefined;
 95в†’  try {
 96в†’    const topicName = `рџ”„ New Session`;
 97в†’    threadId = await createSessionTopic(botFromCtx(ctx), chatId, topicName);
 98в†’
 99в†’    // Let user know we're setting up (spawn + warm-up can take a while)
100в†’    await ctx.api.sendMessage(chatId, `вЏі Setting up session, please wait...`, {
101в†’      message_thread_id: threadId,
102в†’      parse_mode: "HTML",
103в†’    });
104в†’
105в†’    const session = await core.handleNewSession(
106в†’      "telegram",
107в†’      agentName,
108в†’      workspace,
109в†’    );
110в†’    session.threadId = String(threadId);
111в†’
112в†’    // Rename topic with actual agent name
113в†’    const finalName = `рџ”„ ${session.agentName} вЂ” New Session`;
114в†’    try {
115в†’      await ctx.api.editForumTopic(chatId, threadId, { name: finalName });
116в†’    } catch {
117в†’      /* ignore rename failures */
118в†’    }
119в†’
120в†’    await ctx.api.sendMessage(
121в†’      chatId,
122в†’      `вњ… Session started\n` +
123в†’        `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
124в†’        `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>`,
125в†’      {
126в†’        message_thread_id: threadId,
127в†’        parse_mode: "HTML",
128в†’      },
129в†’    );
130в†’
131в†’    // Warm up model cache in background while user types
132в†’    session.warmup().catch((err) => log.error({ err }, "Warm-up error"));
133в†’  } catch (err) {
134в†’    // Clean up orphaned topic if session creation failed
135в†’    if (threadId) {
136в†’      try {
137в†’        await ctx.api.deleteForumTopic(chatId, threadId);
138в†’      } catch {
139в†’        /* ignore cleanup failures */
140в†’      }
141в†’    }
142в†’    const message = err instanceof Error ? err.message : String(err);
143в†’    await ctx.reply(`вќЊ ${escapeHtml(message)}`, { parse_mode: "HTML" });
144в†’  }
145в†’}
