147в†’async function handleNewChat(
148в†’  ctx: Context,
149в†’  core: OpenACPCore,
150в†’  chatId: number,
151в†’): Promise<void> {
152в†’  const threadId = ctx.message?.message_thread_id;
153в†’  if (!threadId) {
154в†’    await ctx.reply(
155в†’      "Use /new_chat inside a session topic to inherit its config.",
156в†’      { parse_mode: "HTML" },
157в†’    );
158в†’    return;
159в†’  }
160в†’
161в†’  try {
162в†’    const session = await core.handleNewChat("telegram", String(threadId));
163в†’    if (!session) {
164в†’      await ctx.reply("No active session in this topic.", {
165в†’        parse_mode: "HTML",
166в†’      });
167в†’      return;
168в†’    }
169в†’
170в†’    const topicName = `рџ”„ ${session.agentName} вЂ” New Chat`;
171в†’    const newThreadId = await createSessionTopic(
172в†’      botFromCtx(ctx),
173в†’      chatId,
174в†’      topicName,
175в†’    );
176в†’
177в†’    await ctx.api.sendMessage(chatId, `вЏі Setting up session, please wait...`, {
178в†’      message_thread_id: newThreadId,
179в†’      parse_mode: "HTML",
180в†’    });
181в†’
182в†’    session.threadId = String(newThreadId);
183в†’
184в†’    await ctx.api.sendMessage(
185в†’      chatId,
186в†’      `вњ… New chat (same agent &amp; workspace)\n` +
187в†’        `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
188в†’        `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>`,
189в†’      {
190в†’        message_thread_id: newThreadId,
191в†’        parse_mode: "HTML",
192в†’      },
193в†’    );
194в†’
195в†’    // Warm up model cache in background while user types
196в†’    session.warmup().catch((err) => log.error({ err }, "Warm-up error"));
197в†’  } catch (err) {
198в†’    const message = err instanceof Error ? err.message : String(err);
199в†’    await ctx.reply(`вќЊ ${escapeHtml(message)}`, { parse_mode: "HTML" });
200в†’  }
201в†’}
