203в†’async function handleCancel(ctx: Context, core: OpenACPCore): Promise<void> {
204в†’  const threadId = ctx.message?.message_thread_id;
205в†’  if (!threadId) return;
206в†’
207в†’  const session = core.sessionManager.getSessionByThread(
208в†’    "telegram",
209в†’    String(threadId),
210в†’  );
211в†’  if (session) {
212в†’    log.info({ sessionId: session.id }, 'Cancel session command')
213в†’    await session.cancel();
214в†’    await ctx.reply("в›” Session cancelled.", { parse_mode: "HTML" });
215в†’  }
216в†’}
217в†’
218в†’async function handleStatus(ctx: Context, core: OpenACPCore): Promise<void> {
219в†’  const threadId = ctx.message?.message_thread_id;
220в†’  if (threadId) {
221в†’    const session = core.sessionManager.getSessionByThread(
222в†’      "telegram",
223в†’      String(threadId),
224в†’    );
225в†’    if (session) {
226в†’      await ctx.reply(
227в†’        `<b>Session:</b> ${escapeHtml(session.name || session.id)}\n` +
228в†’          `<b>Agent:</b> ${escapeHtml(session.agentName)}\n` +
229в†’          `<b>Status:</b> ${escapeHtml(session.status)}\n` +
230в†’          `<b>Workspace:</b> <code>${escapeHtml(session.workingDirectory)}</code>\n` +
231в†’          `<b>Queue:</b> ${session.promptQueue.length} pending`,
232в†’        { parse_mode: "HTML" },
233в†’      );
234в†’    } else {
235в†’      await ctx.reply("No active session in this topic.", {
236в†’        parse_mode: "HTML",
237в†’      });
238в†’    }
239в†’  } else {
240в†’    const sessions = core.sessionManager.listSessions("telegram");
241в†’    const active = sessions.filter(
242в†’      (s) => s.status === "active" || s.status === "initializing",
243в†’    );
244в†’    await ctx.reply(
245в†’      `<b>OpenACP Status</b>\n` +
246в†’        `Active sessions: ${active.length}\n` +
247в†’        `Total sessions: ${sessions.length}`,
248в†’      { parse_mode: "HTML" },
249в†’    );
250в†’  }
251в†’}
252в†’
253в†’async function handleAgents(ctx: Context, core: OpenACPCore): Promise<void> {
254в†’  const agents = core.agentManager.getAvailableAgents();
255в†’  const defaultAgent = core.configManager.get().defaultAgent;
256в†’  const lines = agents.map(
257в†’    (a) =>
258в†’      `вЂў <b>${escapeHtml(a.name)}</b>${a.name === defaultAgent ? " (default)" : ""}\n` +
259в†’      `  <code>${escapeHtml(a.command)} ${a.args.map((arg) => escapeHtml(arg)).join(" ")}</code>`,
260в†’  );
261в†’  const text =
262в†’    lines.length > 0
263в†’      ? `<b>Available Agents:</b>\n\n${lines.join("\n")}`
264в†’      : `<b>Available Agents:</b>\n\nNo agents configured.`;
265в†’  await ctx.reply(text, { parse_mode: "HTML" });
266в†’}
267в†’
268в†’async function handleHelp(ctx: Context): Promise<void> {
269в†’  await ctx.reply(
270в†’    `<b>OpenACP Commands:</b>\n\n` +
271в†’      `/new [agent] [workspace] вЂ” Create new session\n` +
272в†’      `/new_chat вЂ” New chat, same agent &amp; workspace\n` +
273в†’      `/cancel вЂ” Cancel current session\n` +
274в†’      `/status вЂ” Show session/system status\n` +
275в†’      `/agents вЂ” List available agents\n` +
276в†’      `/menu вЂ” Show interactive menu\n` +
277в†’      `/help вЂ” Show this help\n\n` +
278в†’      `Or just chat in the рџ¤– Assistant topic for help!`,
279в†’    { parse_mode: "HTML" },
280в†’  );
281в†’}
282в†’
283в†’// grammy's Context exposes .api (the bot's Api instance) and internally the bot
284в†’// We need access to the bot instance for createSessionTopic (which uses bot.api.createForumTopic).
285в†’// ctx.api is the same Api object as bot.api, so we can pass a minimal shim.
286в†’function botFromCtx(ctx: Context): Bot {
287в†’  // createSessionTopic only uses bot.api.createForumTopic
288в†’  return { api: ctx.api } as unknown as Bot;
289в†’}
290в†’
291в†’// Skill command callback lookup map (short key в†’ session + command)
292в†’interface SkillCallbackEntry {
293в†’  sessionId: string
294в†’  commandName: string
295в†’}
296в†’
297в†’const skillCallbackMap = new Map<string, SkillCallbackEntry>()
298в†’
299в†’export function buildSkillKeyboard(
300в†’  sessionId: string,
301в†’  commands: AgentCommand[],
302в†’): InlineKeyboard {
303в†’  const keyboard = new InlineKeyboard()
304в†’  const sorted = [...commands].sort((a, b) => a.name.localeCompare(b.name))
305в†’  for (let i = 0; i < sorted.length; i++) {
306в†’    const cmd = sorted[i]
307в†’    const key = nanoid(8)
308в†’    skillCallbackMap.set(key, { sessionId, commandName: cmd.name })
309в†’    keyboard.text(`/${cmd.name}`, `s:${key}`)
310в†’    if (i % 2 === 1 && i < sorted.length - 1) {
311в†’      keyboard.row()
312в†’    }
313в†’  }
314в†’  return keyboard
315в†’}
316в†’
317в†’export function clearSkillCallbacks(sessionId: string): void {
318в†’  for (const [key, entry] of skillCallbackMap) {
319в†’    if (entry.sessionId === sessionId) {
320в†’      skillCallbackMap.delete(key)
321в†’    }
322в†’  }
323в†’}
324в†’
325в†’export function setupSkillCallbacks(
326в†’  bot: Bot,
327в†’  core: OpenACPCore,
328в†’): void {
329в†’  bot.callbackQuery(/^s:/, async (ctx) => {
330в†’    try {
331в†’      await ctx.answerCallbackQuery()
332в†’    } catch { /* expired */ }
333в†’
334в†’    const key = ctx.callbackQuery.data.slice(2)
335в†’    const entry = skillCallbackMap.get(key)
336в†’    if (!entry) return
337в†’
338в†’    const session = core.sessionManager.getSession(entry.sessionId)
339в†’    if (!session || session.status !== 'active') return
340в†’
341в†’    await session.enqueuePrompt(`/${entry.commandName}`)
342в†’  })
343в†’}
