348в†’  { command: 'cancel', description: 'Cancel current session' },
349в†’  { command: 'status', description: 'Show status' },
350в†’  { command: 'agents', description: 'List available agents' },
351в†’  { command: 'help', description: 'Help' },
352в†’  { command: 'menu', description: 'Show menu' },
353в†’]
