  1в†’import { Bot } from "grammy";
  2в†’import {
  3в†’  ChannelAdapter,
  4в†’  type OpenACPCore,
  5в†’  type OutgoingMessage,
  6в†’  type PermissionRequest,
  7в†’  type NotificationMessage,
  8в†’  type Session,
  9в†’  type AgentCommand,
 10в†’} from "../../core/index.js";
 11в†’import { createChildLogger } from "../../core/log.js";
 12в†’const log = createChildLogger({ module: "telegram" });
 13в†’import type { TelegramChannelConfig } from "./types.js";
 14в†’import { MessageDraft } from "./streaming.js";
 15в†’import {
 16в†’  ensureTopics,
 17в†’  createSessionTopic,
 18в†’  renameSessionTopic,
 19в†’} from "./topics.js";
 20в†’import {
 21в†’  setupCommands,
 22в†’  setupMenuCallbacks,
 23в†’  setupSkillCallbacks,
 24в†’  buildMenuKeyboard,
 25в†’  buildSkillKeyboard,
 26в†’  clearSkillCallbacks,
 27в†’  STATIC_COMMANDS,
 28в†’} from "./commands.js";
 29в†’import { PermissionHandler } from "./permissions.js";
 30в†’import {
 31в†’  spawnAssistant,
 32в†’  handleAssistantMessage,
 33в†’  redirectToAssistant,
 34в†’} from "./assistant.js";
 35в†’import {
 36в†’  escapeHtml,
 37в†’  formatToolCall,
 38в†’  formatToolUpdate,
 39в†’  formatPlan,
 40в†’  formatUsage,
 41в†’} from "./formatting.js";
 42в†’
 43в†’export class TelegramAdapter extends ChannelAdapter {
 44в†’  private bot!: Bot;
 45в†’  private telegramConfig: TelegramChannelConfig;
 46в†’  private sessionDrafts: Map<string, MessageDraft> = new Map();
 47в†’  private toolCallMessages: Map<
 48в†’    string,
 49в†’    Map<string, { msgId: number; name: string; kind?: string }>
 50в†’  > = new Map(); // sessionId в†’ (toolCallId в†’ state)
 51в†’  private permissionHandler!: PermissionHandler;
 52в†’  private assistantSession: Session | null = null;
 53в†’  private notificationTopicId!: number;
 54в†’  private assistantTopicId!: number;
 55в†’  private skillMessages: Map<string, number> = new Map(); // sessionId в†’ pinned messageId
 56в†’
 57в†’  constructor(core: OpenACPCore, config: TelegramChannelConfig) {
 58в†’    super(core, config as never);
 59в†’    this.telegramConfig = config;
 60в†’  }
 61в†’
 62в†’  async start(): Promise<void> {
 63в†’    this.bot = new Bot(this.telegramConfig.botToken, { client: { fetch } });
 64в†’
 65в†’    // Global error handler вЂ” prevent unhandled errors from crashing the bot
 66в†’    this.bot.catch((err) => {
 67в†’      const rootCause = err.error instanceof Error ? err.error : err;
 68в†’      log.error({ err: rootCause }, "Telegram bot error");
 69в†’    });
 70в†’
 71в†’    // Ensure allowed_updates includes callback_query on every poll.
 72в†’    // bot.start() passes allowed_updates, but grammY only sends it on the first
 73в†’    // getUpdates call. Subsequent polls may omit the parameter, causing Telegram
 74в†’    // to fall back to its default (which excludes callback_query). This transformer
 75в†’    // guarantees callback_query is always requested.
 76в†’    this.bot.api.config.use((prev, method, payload, signal) => {
 77в†’      if (method === "getUpdates") {
 78в†’        const p = payload as never as Record<string, unknown>;
 79в†’        p.allowed_updates = (p.allowed_updates as string[] | undefined) ?? [
 80в†’          "message",
 81в†’          "callback_query",
 82в†’        ];
 83в†’      }
 84в†’      return prev(method, payload, signal);
 85в†’    });
 86в†’
 87в†’    // Register static commands for Telegram autocomplete (scoped to this chat)
 88в†’    await this.bot.api.setMyCommands(STATIC_COMMANDS, {
 89в†’      scope: { type: "chat", chat_id: this.telegramConfig.chatId },
 90в†’    });
 91в†’
 92в†’    // Middleware: only accept updates from configured chatId
 93в†’    this.bot.use((ctx, next) => {
 94в†’      const chatId = ctx.chat?.id ?? ctx.callbackQuery?.message?.chat?.id;
 95в†’      if (chatId !== this.telegramConfig.chatId) return;
 96в†’      return next();
 97в†’    });
 98в†’
 99в†’    // Ensure system topics exist
100в†’    const topics = await ensureTopics(
101в†’      this.bot,
102в†’      this.telegramConfig.chatId,
103в†’      this.telegramConfig,
104в†’      async (updates) => {
105в†’        // Save topic IDs to config
106в†’        await (this.core as OpenACPCore).configManager.save({
107в†’          channels: { telegram: updates },
108в†’        });
109в†’      },
110в†’    );
111в†’    this.notificationTopicId = topics.notificationTopicId;
112в†’    this.assistantTopicId = topics.assistantTopicId;
113в†’
114в†’    // Setup permission handler (instance only, callback registered later)
115в†’    this.permissionHandler = new PermissionHandler(
116в†’      this.bot,
117в†’      this.telegramConfig.chatId,
118в†’      (sessionId) =>
119в†’        (this.core as OpenACPCore).sessionManager.getSession(sessionId),
120в†’      (notification) => this.sendNotification(notification),
121в†’    );
122в†’
123в†’    // Callback registration order matters!
124в†’    // Specific regex handlers first, catch-all last.
125в†’    setupSkillCallbacks(this.bot, this.core as OpenACPCore);
126в†’    setupMenuCallbacks(
127в†’      this.bot,
128в†’      this.core as OpenACPCore,
129в†’      this.telegramConfig.chatId,
130в†’    );
131в†’    setupCommands(
132в†’      this.bot,
133в†’      this.core as OpenACPCore,
134в†’      this.telegramConfig.chatId,
135в†’    );
136в†’    this.permissionHandler.setupCallbackHandler();
137в†’
138в†’    // Setup message routing
139в†’    this.setupRoutes();
140в†’
141в†’    // Start bot polling
142в†’    this.bot.start({
143в†’      allowed_updates: ["message", "callback_query"],
144в†’      onStart: () =>
145в†’        log.info(
146в†’          { chatId: this.telegramConfig.chatId },
147в†’          "Telegram bot started",
148в†’        ),
149в†’    });
150в†’
151в†’    // Spawn assistant (after bot is started so it can send messages)
152в†’    try {
153в†’      this.assistantSession = await spawnAssistant(
154в†’        this.core as OpenACPCore,
155в†’        this,
156в†’        this.assistantTopicId,
157в†’      );
158в†’    } catch (err) {
159в†’      log.error({ err }, "Failed to spawn assistant");
160в†’    }
161в†’
162в†’    // Send welcome message with menu to assistant topic
163в†’    try {
164в†’      const config = (this.core as OpenACPCore).configManager.get();
165в†’      const agents = (
166в†’        this.core as OpenACPCore
167в†’      ).agentManager.getAvailableAgents();
168в†’      const agentList = agents
169в†’        .map(
170в†’          (a) =>
171в†’            `${escapeHtml(a.name)}${a.name === config.defaultAgent ? " (default)" : ""}`,
172в†’        )
173в†’        .join(", ");
174в†’      const workspace = escapeHtml(config.workspace.baseDir);
175в†’
176в†’      const welcomeText =
177в†’        `рџ‘‹ <b>OpenACP Assistant</b> is online.\n\n` +
178в†’        `Available agents: ${agentList}\n` +
179в†’        `Workspace: <code>${workspace}</code>\n\n` +
180в†’        `<b>Select an action:</b>`;
181в†’
182в†’      await this.bot.api.sendMessage(this.telegramConfig.chatId, welcomeText, {
183в†’        message_thread_id: this.assistantTopicId,
184в†’        parse_mode: "HTML",
185в†’        reply_markup: buildMenuKeyboard(),
186в†’      });
187в†’    } catch (err) {
188в†’      log.warn({ err }, "Failed to send welcome message");
189в†’    }
190в†’  }
191в†’
192в†’  async stop(): Promise<void> {
193в†’    if (this.assistantSession) {
194в†’      await this.assistantSession.destroy();
195в†’    }
196в†’    await this.bot.stop();
197в†’    log.info("Telegram bot stopped");
198в†’  }
199в†’
200в†’  private setupRoutes(): void {
201в†’    this.bot.on("message:text", async (ctx) => {
202в†’      const threadId = ctx.message.message_thread_id;
203в†’
204в†’      // General topic or no thread в†’ redirect to assistant
205в†’      if (!threadId) {
206в†’        const html = redirectToAssistant(
207в†’          this.telegramConfig.chatId,
208в†’          this.assistantTopicId,
209в†’        );
210в†’        await ctx.reply(html, { parse_mode: "HTML" });
211в†’        return;
212в†’      }
213в†’
214в†’      // Notification topic в†’ ignore
215в†’      if (threadId === this.notificationTopicId) return;
216в†’
217в†’      // Assistant topic в†’ send typing indicator and forward to assistant session
218в†’      if (threadId === this.assistantTopicId) {
219в†’        ctx.replyWithChatAction("typing").catch(() => {});
220в†’        handleAssistantMessage(this.assistantSession, ctx.message.text).catch(
221в†’          (err) => log.error({ err }, "Assistant error"),
222в†’        );
223в†’        return;
224в†’      }
225в†’
226в†’      // Session topic в†’ send typing indicator and forward to core
227в†’      ctx.replyWithChatAction("typing").catch(() => {});
228в†’      (this.core as OpenACPCore)
229в†’        .handleMessage({
230в†’          channelId: "telegram",
231в†’          threadId: String(threadId),
232в†’          userId: String(ctx.from.id),
233в†’          text: ctx.message.text,
234в†’        })
235в†’        .catch((err) => log.error({ err }, "handleMessage error"));
236в†’    });
237в†’  }
238в†’
239в†’  // --- ChannelAdapter implementations ---
240в†’
241в†’  async sendMessage(
242в†’    sessionId: string,
243в†’    content: OutgoingMessage,
244в†’  ): Promise<void> {
245в†’    // log.debug({ sessionId, type: content.type }, "Sending message to Telegram");
246в†’    const session = (this.core as OpenACPCore).sessionManager.getSession(
247в†’      sessionId,
248в†’    );
249в†’    if (!session) return;
250в†’    const threadId = Number(session.threadId);
251в†’
252в†’    switch (content.type) {
253в†’      case "thought": {
254в†’        // Skip thought/thinking content вЂ” it's internal agent reasoning
255в†’        // Users don't need to see it
256в†’        break;
257в†’      }
258в†’
259в†’      case "text": {
260в†’        let draft = this.sessionDrafts.get(sessionId);
261в†’        if (!draft) {
262в†’          draft = new MessageDraft(
263в†’            this.bot,
264в†’            this.telegramConfig.chatId,
265в†’            threadId,
266в†’          );
267в†’          this.sessionDrafts.set(sessionId, draft);
268в†’        }
269в†’        draft.append(content.text);
270в†’        break;
271в†’      }
272в†’
273в†’      case "tool_call": {
274в†’        await this.finalizeDraft(sessionId);
275в†’        const meta = content.metadata as never as {
276в†’          id: string;
277в†’          name: string;
278в†’          kind?: string;
279в†’          status?: string;
280в†’          content?: unknown;
281в†’        };
282в†’        const msg = await this.bot.api.sendMessage(
283в†’          this.telegramConfig.chatId,
284в†’          formatToolCall(meta),
285в†’          {
286в†’            message_thread_id: threadId,
287в†’            parse_mode: "HTML",
288в†’            disable_notification: true,
289в†’          },
290в†’        );
291в†’        if (!this.toolCallMessages.has(sessionId)) {
292в†’          this.toolCallMessages.set(sessionId, new Map());
293в†’        }
294в†’        this.toolCallMessages.get(sessionId)!.set(meta.id, {
295в†’          msgId: msg.message_id,
296в†’          name: meta.name,
297в†’          kind: meta.kind,
298в†’        });
299в†’        break;
300в†’      }
301в†’
302в†’      case "tool_update": {
303в†’        const meta = content.metadata as never as {
304в†’          id: string;
305в†’          name: string;
306в†’          kind?: string;
307в†’          status: string;
308в†’          content?: unknown;
309в†’        };
310в†’        const toolState = this.toolCallMessages.get(sessionId)?.get(meta.id);
311в†’        if (toolState) {
312в†’          // Merge name/kind from original tool_call
313в†’          const merged = {
314в†’            ...meta,
315в†’            name: meta.name || toolState.name,
316в†’            kind: meta.kind || toolState.kind,
317в†’          };
318в†’          try {
319в†’            await this.bot.api.editMessageText(
320в†’              this.telegramConfig.chatId,
321в†’              toolState.msgId,
322в†’              formatToolUpdate(merged),
323в†’              { parse_mode: "HTML" },
324в†’            );
325в†’          } catch {
326в†’            /* edit failed */
327в†’          }
328в†’        }
329в†’        break;
330в†’      }
331в†’
332в†’      case "plan": {
333в†’        await this.finalizeDraft(sessionId);
334в†’        await this.bot.api.sendMessage(
335в†’          this.telegramConfig.chatId,
336в†’          formatPlan(
337в†’            content.metadata as never as {
338в†’              entries: Array<{ content: string; status: string }>;
339в†’            },
340в†’          ),
341в†’          {
342в†’            message_thread_id: threadId,
343в†’            parse_mode: "HTML",
344в†’            disable_notification: true,
345в†’          },
346в†’        );
347в†’        break;
348в†’      }
349в†’
350в†’      case "usage": {
351в†’        // Show usage stats
352в†’        await this.bot.api.sendMessage(
353в†’          this.telegramConfig.chatId,
354в†’          formatUsage(
355в†’            content.metadata as never as {
356в†’              tokensUsed?: number;
357в†’              contextSize?: number;
358в†’              cost?: { amount: number; currency: string };
359в†’            },
360в†’          ),
361в†’          {
362в†’            message_thread_id: threadId,
363в†’            parse_mode: "HTML",
364в†’            disable_notification: true,
365в†’          },
366в†’        );
367в†’        break;
368в†’      }
369в†’
370в†’      case "session_end": {
371в†’        await this.finalizeDraft(sessionId);
372в†’        this.sessionDrafts.delete(sessionId);
373в†’        this.toolCallMessages.delete(sessionId);
374в†’        await this.cleanupSkillCommands(sessionId);
375в†’        await this.bot.api.sendMessage(
376в†’          this.telegramConfig.chatId,
377в†’          `вњ… <b>Done</b>`,
378в†’          {
379в†’            message_thread_id: threadId,
380в†’            parse_mode: "HTML",
381в†’            disable_notification: true,
382в†’          },
383в†’        );
384в†’        break;
385в†’      }
386в†’
387в†’      case "error": {
388в†’        await this.finalizeDraft(sessionId);
389в†’        await this.bot.api.sendMessage(
390в†’          this.telegramConfig.chatId,
391в†’          `вќЊ <b>Error:</b> ${escapeHtml(content.text)}`,
392в†’          {
393в†’            message_thread_id: threadId,
394в†’            parse_mode: "HTML",
395в†’            disable_notification: true,
396в†’          },
397в†’        );
398в†’        break;
399в†’      }
400в†’    }
401в†’  }
402в†’
403в†’  async sendPermissionRequest(
404в†’    sessionId: string,
405в†’    request: PermissionRequest,
406в†’  ): Promise<void> {
407в†’    log.info({ sessionId, requestId: request.id }, "Permission request sent");
408в†’    const session = (this.core as OpenACPCore).sessionManager.getSession(
409в†’      sessionId,
410в†’    );
411в†’    if (!session) return;
412в†’    await this.permissionHandler.sendPermissionRequest(session, request);
413в†’  }
